import { Grid, Typography, Box , Link} from "@mui/material";

const skills = [
  {
    id: 1,
    name: "Build Web applications",
    example:'https://travelzmate.com/'
  },
  {
    id: 2,
    name: "Build mobile applications",
    example:'https://ziqaq.ps/landing'
  },
  {
    id: 3,
    name: "Test website for usability ",

  },
  {
    id: 4,
    name: "Client side development ",

  },
];
export const Skills = () => {
  return (
    <Grid container mt={2}>
      <Grid item xs={6}>
        <Box  p={2} sx={{border:'5px solid black', borderRadius:'20px 10px'}}>
          <Typography variant="h4" >What can I do</Typography>
          {skills.map((skill) => (
            <Box component="div" key={skill.id} mt={2}>
              <Typography variant="h6" color="textPrimary">
              &#x2714; {skill.name}

              </Typography>
              <Link href={skill.example} >
            {skill?.example}

              </Link>
            </Box>
          ))}
        </Box>
      </Grid>
      <Grid item xs={6}>
      <Box  p={2} sx={{border:'5px solid green', borderRadius:'10px 20px'}}>
          <Typography variant="h4">Skills</Typography>
          {skills.map((skill) => (
            <Box component="div" key={skill.id} mt={2}>
              <Typography variant="h6" color="textPrimary">
              &#x2714; {skill.name}

              </Typography>

            </Box>
          ))}
        </Box>
      </Grid>
    </Grid>
  );
};
